import urllib.parse

def login_redirect(request):
    # Get the intended destination from the request
    intended_destination = request.GET.get('intended_destination')

    # Check if the intended destination is a valid URL
    try:
        urllib.parse.urlparse(intended_destination)
    except ValueError:
        # If the intended destination is not a valid URL, redirect to the home page
        return HttpResponseRedirect('/')

    # If the intended destination is a valid URL, check if it is a safe URL
    if not urllib.parse.urlunparse(intended_destination).startswith('https://'):
        # If the intended destination is not a safe URL, redirect to the home page
        return HttpResponseRedirect('/')

    # If the intended destination is a valid and safe URL, redirect to it
    return HttpResponseRedirect(intended_destination)